        "\u05d1\u05e9\u05e0\u05d9\u05dd \u05d2' \u05d5\u05d5' \u2014 \u05de\u05e2\u05e9\u05e8 \u05e2\u05e0\u05d9 \u05dc\u05e2\u05e0\u05d9\u05d9\u05dd. \U0001f34e\U0001f91d "
        "\u05d2\u05dd \u05d1\u05e9\u05d5\u05e7 \u05d9\u05e9\u05e8\u05d0\u05dc\u05d9 \u05d0\u05e4\u05e9\u05e8 \u05dc\u05e8\u05d0\u05d5\u05ea \u05d8\u05d1\u05dc \u05e9\u05dc\u05d0 \u05e2\u05d1\u05e8 \u05d4\u05e4\u05e8\u05d3\u05d4. "
        "\u05d4\u05d4\u05dc\u05db\u05d4 \u05d4\u05de\u05d5\u05d3\u05e8\u05e0\u05d9\u05ea \u05e9\u05d5\u05de\u05e8\u05ea \u05e2\u05dc \u05d4\u05de\u05e1\u05d5\u05e8\u05ea \u05d1\u05d4\u05e4\u05e8\u05d3\u05d5\u05ea \u05e1\u05de\u05dc\u05d9\u05d5\u05ea. "
